import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedExample {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly encode user input using ESAPI's HTML entity encoding
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedInput = codec.encode(userInput);

        // Output the encoded user input to prevent XSS attacks
        System.out.println("<p>User Input: " + encodedInput + "</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
